// sounds.js
class AudioManager {
  constructor() {
    this.sounds = {};
    this.music = null;
  }

  loadSound(name, url) {
    this.sounds[name] = new Audio(url);
  }

  playSound(name) {
    if (this.sounds[name]) {
      this.sounds[name].currentTime = 0;
      this.sounds[name].play().catch(e => console.error("Error al reproducir sonido:", e));
    }
  }

  playMusic(url) {
    if (!this.music) {
      this.music = new Audio(url);
      this.music.loop = true;
      this.music.play().catch(e => console.error("Error al reproducir música:", e));
    }
  }

  stopMusic() {
    if (this.music) {
      this.music.pause();
      this.music.currentTime = 0;
    }
  }
}

const audioManager = new AudioManager();

// Cargar sonidos
audioManager.loadSound("select", "data:audio/mpeg;base64,");
audioManager.loadSound("click", "data:audio/mpeg;base64,");
